    // Show typing indicator
    await sock.sendPresenceUpdate('composing', jid)

    try {
      // --- Step 3: Classify intent ---
      const intent = await classifyIntent(text, hasDocument)
      console.log(`[${jid}] Intent: ${intent}`)

      let reply

      // --- Step 4: Route to service based on intent ---
      switch (intent) {
        case 'ENCODE_DATA': {
          if (!documentMessage) {
            reply = 'Please attach a spreadsheet file (.xlsx or .csv) along with your message so I can process it.'
            break
          }

          // Download the document buffer
          const buffer = await downloadMediaMessage(msg, 'buffer', {}, {
            logger: P({ level: 'silent' }),
            reuploadRequest: sock.updateMediaMessage,
          })

          const mimetype = documentMessage.mimetype || ''
          const fileName = documentMessage.fileName || ''

          const parseResult = parseDocument(buffer, mimetype, fileName)

          if (!parseResult.success) {
            reply = parseResult.message
            break
          }

          // Pass parsed data to grading automation
          const gradeResult = await runGrading({ data: parseResult.data })
          reply = gradeResult.message
          break
        }

        case 'SUMMARIZE_TWITTER': {
          const twitterResult = await summarizeTwitter()
          if (twitterResult.success) {
            reply = `Here are the latest tweets from your timeline:\n\n${twitterResult.tweets}`
          } else {
            reply = twitterResult.message
          }
          break
        }

        case 'ANSWER_ASSIGNMENT': {
          const academicResult = await answerAssignment(text, ollama)
          if (academicResult.success) {
            reply = academicResult.answer
          } else {
            reply = academicResult.message
          }
          break
        }

        case 'CHAT':
